#
# AdjustUnitOutageRate_AEO.jl - Assigns output rates from AEO to future values of UnOR.
#
using EnergyModel

module AdjustUnitOutageRate_AEO

import ...EnergyModel: ReadDisk,WriteDisk,Select
import ...EnergyModel: HisTime,ITime,MaxTime,First,Future,Final,Yr
import ...EnergyModel: @finite_math,finite_inverse,finite_divide,finite_power,finite_exp,finite_log
import ...EnergyModel: DB

const VariableArray{N} = Array{Float32,N} where {N}
const SetArray = Vector{String}

Base.@kwdef struct EControl
  db::String
  BCNameDB::String = ReadDisk(db,"MainDB/BCNameDB") # Base Case Name

  Month::SetArray = ReadDisk(db,"MainDB/MonthKey")
  MonthDS::SetArray = ReadDisk(db,"MainDB/MonthDS")
  Months::Vector{Int} = collect(Select(Month))
  Node::SetArray = ReadDisk(db, "MainDB/NodeKey")
  Plant::SetArray = ReadDisk(db, "MainDB/PlantKey")
  TimeP::SetArray = ReadDisk(db,"MainDB/TimePKey")
  TimePs::Vector{Int} = collect(Select(TimeP))
  Unit::SetArray = ReadDisk(db,"MainDB/UnitKey")
  Units::Vector{Int} = collect(Select(Unit))
  Year::SetArray = ReadDisk(db,"MainDB/YearKey")
  YearDS::SetArray = ReadDisk(db,"MainDB/YearDS")
  Years::Vector{Int} = collect(Select(Year))

  UnArea::Array{String} = ReadDisk(db,"EGInput/UnArea") # [Unit] Area Pointer
  UnEAF::VariableArray{3} = ReadDisk(db,"EGInput/UnEAF") # [Unit,Month,Year] Energy Avaliability Factor (MWh/MWh)
  UnGenCo::Array{String} = ReadDisk(db,"EGInput/UnGenCo") # [Unit] Generating Company
  UnNation::Array{String} = ReadDisk(db,"EGInput/UnNation") # [Unit] Nation
  UnNode::Array{String} = ReadDisk(db,"EGInput/UnNode") # [Unit] Transmission Node
  UnOR::VariableArray{4} = ReadDisk(db,"EGInput/UnOR") #[Unit,TimeP,Month,Year]  Outage Rate (MW/MW)

  UnPlant::Array{String} = ReadDisk(db,"EGInput/UnPlant") # [Unit] Plant Type

  # Scratch Variables
  EAFAEO::VariableArray{2} = zeros(Float32,length(Node),length(Year)) # [Node,Year] Energy Availability Factor for Peak Hydro Implied by AEO (MW/MW)
  OutageRateAEO::VariableArray{3} = zeros(Float32,length(Node),length(Plant),length(Year)) # [Node,Plant,Year] Outage Rate Implied by AEO Capacity Factors (MW/MW)
end

function GetUnitSets(data,unit)
  (; Node,Plant) = data
  (; UnNode,UnPlant) = data

  #
  # This procedure selects the sets for a particular unit
  #
  # EmptyString = ""
  if (UnPlant[unit] !== "Null") && (UnNode[unit] !== "Null")
    # genco = Select(GenCo,UnGenCo[unit])
    plant = Select(Plant,UnPlant[unit])
    node = Select(Node,UnNode[unit])
    # area = Select(Area,UnArea[unit])
    # ecc = Select(ECC,UnSector[unit])
  else
    plant=first(Plant)
    node=first(Node)
  end
  return plant,node
end

